const CACHE_NAME='dependencies-cache';self.addEventListener('install',async event=>{console.log('[install] Service worker registration started.');event.waitUntil((async()=>{try{const cache=await caches.open(CACHE_NAME);const response=await fetch('file-list.json');const files=await response.json();console.log('[install] Caching files:',files);await cache.addAll(files);console.log('[install] All resources cached. Service Worker installed!');await self.skipWaiting()}catch(error){console.error('[install] Failed to cache:',error)}})())});self.addEventListener('fetch',event=>{event.respondWith(caches.match(event.request).then(response=>{if(response){console.log('[fetch] Cache hit:',event.request.url);return response}console.log('[fetch] Fetching from network:',event.request.url);return fetch(event.request)}))});self.addEventListener('activate',event=>{console.log('[activate] Activating service worker and claiming clients.');event.waitUntil(self.clients.claim())});
